INSERT INTO public.photos VALUES (22336, 'Jard├¡n de Invierno 1961', 'Cuadro de jota en el Jard├¡n de Invierno del Cabezo de Buenavista de Zaragoza. Postal, 1961.', 1961, 1961, 1961, 'Anos 60', 'UNIVERSIDAD', 41.63172600, -0.89277800, '0101000020E610000041D3122BA391ECBF3604C765DCD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19553853706.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19553853706.webp', 'https://www.flickr.com/photos/zaragozaantigua/19553853706/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20932, 'Aljafer├¡a 1500', 'Dibujo realizado hacia 1875 que ilustra el posible aspecto, desde el noreste, del palacio de la Aljafer├¡a en la ├®poca de los Reyes Cat├│licos, con su original recinto amurallado, la torre del Homenaje culminada en mirador y la iglesia de la parroquia de San Mart├¡n. Fuente visual: www.cortesaragon.es/', 1500, 1500, 1500, 'Siglo XIX', 'DELICIAS', 41.65656600, -0.89697300, '0101000020E6100000E8A38CB800B4ECBF30D5CC5A0AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25174985037.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25174985037.webp', 'https://www.flickr.com/photos/zaragozaantigua/25174985037/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20958, 'Puerta del Portillo c.1800', '"Puerta del Portillo", Antonio Callaved, 2012. De origen medieval, fue destruida en los sitios y vuelta a construir, hasta ser derribada en 1868. A la derecha, iglesia del Portillo. Se ubicaba en la actual calle de Conde de Aranda. Fuente: pinturascallaved.wordpress.com/5-mi-pintura-en-la-filatelia/', 1800, 1800, 1800, 'Siglo XIX', 'DELICIAS', 41.65597400, -0.89272400, '0101000020E610000075560BEC3191ECBF5E83BEF4F6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15280181625.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15280181625.webp', 'https://www.flickr.com/photos/zaragozaantigua/15280181625/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21000, 'N.┬¬ S.┬¬ del Portillo 1827', 'Fotograf├¡a realizada sobre 1880 por Anselmo Mar├¡a Coyne del dibujo que representaba el proyecto de rehabilitaci├│n de la tardobarroca iglesia parroquial de Nuestra Se├▒ora del Portillo, realizado en 1827 por el arquitecto Jos├® de Yarza y Mi├▒ana al objeto de reconstruirla tras los da├▒os sufridos durante los asedios franceses de 1808-1809. En este caso, se trata del dibujo de la fachada principal de la iglesia, con el gran p├│rtico en arco de medio punto por el que se ingresa a su interior desde la plaza del Portillo. Esta obra se mantuvo inconclusa hasta la d├®cada de los a├▒os ochenta del pasado siglo XX, cuando el arquitecto Jos├® Manuel P├®rez Latorre reinterpret├│ el proyecto dej├índolo tal y como ahora es visible. Jos├® de Yarza y Mi├▒ana particip├│ tambi├®n en los proyectos de reconstrucci├│n (algunos realizados, otros no) de un buen n├║mero de iglesias, conventos y monasterios afectados por los referidos asedios, como la iglesia y convento de Santa M├│nica, el Real Monasterio de Santa Engracia, el convento de los Capuchinos, el convento de los Trinitarios Descalzos, y la iglesia parroquial de N.┬¬ S.┬¬ de Altab├ís. Fuente visual: Archivo Coyne, en AHPZ', 1827, 1827, 1827, 'Siglo XIX', 'DELICIAS', 41.65586500, -0.89282000, '0101000020E6100000FCDEA63FFB91ECBFA7CB6262F3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45008437781.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45008437781.webp', 'https://www.flickr.com/photos/zaragozaantigua/45008437781/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21048, 'Cuartel Aljafer├¡a 1877', 'Archivo RUIZ VERNACCI, Jean Laurent y C├¡a. 1874-1877. "Vista del Cuartel de la Aljafer├¡a con soldados." El Regimiento de Galicia, alojado en este "Cuartel", posa en disposici├│n de revista.', 1877, 1877, 1877, 'Siglo XIX', 'DELICIAS', 41.65614400, -0.89646900, '0101000020E610000022179CC1DFAFECBFBABBCE86FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14679640338.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14679640338.webp', 'https://www.flickr.com/photos/zaragozaantigua/14679640338/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21064, 'La Aljafer├¡a 1877', 'Archivo RUIZ VERNACCI, Jean Laurent y C├¡a. 1874-1877. "Vista del Cuartel de la Aljafer├¡a." El Regimiento de Galicia, alojado en este "Cuartel", a├║n no ha salido para posar en posici├│n de revista, delante del antiguo Palacio de la Alegr├¡a. El fot├│grafo aprovecha para realizar una captura de prueba.', 1877, 1877, 1877, 'Siglo XIX', 'DELICIAS', 41.65617600, -0.89651200, '0101000020E6100000F4160FEF39B0ECBFC6353E93FDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15503036261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15503036261.webp', 'https://www.flickr.com/photos/zaragozaantigua/15503036261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21104, 'Plaza del Portillo 1889', '"Saragosse. Vue g├®nerale". J. L├®vy et Cie. Una d├®cada despu├®s de que J. Laurent et Cie. nos impactara con su fenomenal vista panor├ímica de la ciudad desde las alturas de la iglesia del Portillo, J. Levy et Cie. se suben tambi├®n al mismo punto para realizar una ├║nica captura, no menos interesante. A los pies sigue la circular plaza del Portillo, a la que desembocan las paralelas calles del Portillo y Agustina de Arag├│n. A la izquierda, inmediatos, algunos cambios: el muro de la huertas y convento de Santa In├®s, ya est├ín retranqueados como signo de que el ensanchamiento de la estrecha calle del Portillo va en serio. Su estrechez no hab├¡a sido problema durante siglos: por ejemplo, cuando un monarca entraba por la puerta del Portillo, giraba por Santa In├®s, giraba de nuevo hacia San Pablo, y llegaba directo a la plaza del Mercado. Ahora se argumentaba que era necesario dar amplitud a la calle como acceso directo al Coso, lo que requer├¡a ampliarla, sanearla, y de paso, dar alg├║n pelotazo urban├¡stico. Dicho y hecho, aunque costar├¡a un tiempo. Este ensanchamiento se llevar├¡a una parte de la antigua "Casa de la Galera", el complejo que hace esquina con Santa In├®s, que luego desempe├▒├│ funciones de c├írcel, y que desde 1883 hab├¡a sido reconvertido en escuela de ni├▒os... Los mismos recortes afectaron a muchos edificios de esta calle, hasta el Coso. Esta es la g├®nesis de la posteriormente denominada calle Conde de Aranda. Al fondo, sobre los tejados, la l├¡nea de torres de la ciudad, cambiante seg├║n el ritmo de los derribos. De izquierda a derecha: el Pilar, San Pablo, Santa Isabel, San Salvador y su cimborrio, la Torre Nueva (pre-muerta), San Felipe y Santiago el Menor, las Escuelas P├¡as, San Juan y San Pedro, La Magdalena, el palacio de Morata, San Gil, San Carlos, San Miguel, y San Ildefonso. Cerca de ├®sta, apenas cuatro a├▒os antes a├║n se levantaba la torre del antiguo convento de los M├¡nimos de la Victoria. Fuente visual: Zaragoza en la mirada ajena. Cortes de Arag├│n, 2012', 1889, 1889, 1889, 'Siglo XIX', 'DELICIAS', 41.65564900, -0.89266600, '0101000020E61000004E098849B890ECBFDA53724EECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19115472282.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19115472282.webp', 'https://www.flickr.com/photos/zaragozaantigua/19115472282/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21112, 'Aljafer├¡a 1889', '"Saragosse. Caserne de l''Aljaferia". Antiguo palacio, cuando era dependencia cuartelaria del Ministerio de la Guerra. Imagen capturada desde la carretera a Madrid. Sobresalen, al fondo, la torre del homenaje, y los restos desmochados de la torrecilla de la iglesia de San Mart├¡n. Fuente: J. L├®vy et Cie, en "Zaragoza en la mirada ajena", Cortes de Arag├│n, 2012.', 1889, 1889, 1889, 'Siglo XIX', 'DELICIAS', 41.65617600, -0.89651200, '0101000020E6100000F4160FEF39B0ECBFC6353E93FDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22750553871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22750553871.webp', 'https://www.flickr.com/photos/zaragozaantigua/22750553871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21126, 'La Aljafer├¡a 1889', '"Puerta trasera del oratorio isl├ímico de la Aljafer├¡a". Esta puerta se encuentra hoy cegada, frente a la entrada principal del palacio, en el patio de San Mart├¡n. Fuente: J. L├®vy et Cie, en "Zaragoza en la mirada ajena", Cortes de Arag├│n, 2012.', 1889, 1889, 1889, 'Siglo XIX', 'DELICIAS', 41.65671000, -0.89669400, '0101000020E61000001F9F909DB7B1ECBF637AC2120FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40289731665.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40289731665.webp', 'https://www.flickr.com/photos/zaragozaantigua/40289731665/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21221, 'Aljafer├¡a 1900', 'En domingo, y desde la Ribera Baja, una excursi├│n a Zaragoza a merendar y tirar unas fotos, que el tiempo acompa├▒a. La merienda, ya ha tendido lugar en los tranquilos y arbolados alrededores del cuartel de la Aljafer├¡a, por la parte de detr├ís, no lejos del amistoso polvor├¡n donde unos a├▒os despu├®s se habilitar├í el "hom├│dromo", o minicampo de maniobras para los efectivos cuartelarios. El posado, perfectamente ordenado de menor a mayor importancia (chavaler├¡a, mujeres, hombre, cura) junto a la v├¡a del ferrocarril de Madrid a Barcelona, no lejos del Camino de Herederos y del Convento de los Carmelitas Descalzos de San Jos├®, apenas a unas decenas de metros. Al fondo, panorama urbano del momento. A la izquierda, la rotunda silueta del castillo-cuartel. Por encima sobresale la torre de Santiago del Pilar, junto a la mole de la Torre del Trovador. A la derecha, c├║pula y torrecillas de la Real Casa de la Misericordia. El humo, de la activa Fundici├│n Averly. Fuente visual: quintodeebro.com/ Familia Florencio Jardiel Dobato', 1900, 1900, 1900, 'Anos 1900', 'DELICIAS', 41.65670500, -0.89965500, '0101000020E610000027DA5548F9C9ECBF520FD1E80ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15915606913.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15915606913.webp', 'https://www.flickr.com/photos/zaragozaantigua/15915606913/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21263, 'El Portillo 1907', 'Postal. "Colecci├│n Patria y Fe n├║m. 7, Zaragoza 1908 - Centenario de los Sitios", 1907. "Esta puerta es la que Agustina de Arag├│n defendi├│ heroicamente, en el ataque del 2 de julio, salvando a la ciudad en uno de los momentos de mayor peligro." Vista del emplazamiento de la antigua puerta del Portillo, en la esquina de la iglesia del Portillo con la calle del Conde de Aranda y el paseo de Mar├¡a Agust├¡n actuales. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'DELICIAS', 41.65622400, -0.89352900, '0101000020E6100000F8E12021CA97ECBFD76CE525FFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20767895975.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20767895975.webp', 'https://www.flickr.com/photos/zaragozaantigua/20767895975/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21664, 'Plaza del Portillo 1930', '"Iglesia de Nuestra Se├▒ora del Portillo".', 1930, 1930, 1930, 'Anos 30', 'DELICIAS', 41.65575900, -0.89275700, '0101000020E610000064CDC8207791ECBF628731E9EFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14681281839.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14681281839.webp', 'https://www.flickr.com/photos/zaragozaantigua/14681281839/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21692, 'Plaza del Portillo 1930', '"Plaza del Portillo y monumento a Agustina de Arag├│n". Imagen tomada con la iglesia del Portillo como tel├│n de fondo del monumento. M├ís al fondo, a la derecha, la calle del Conde Aranda, con vista de los muros tras los que estaban los enormes huertos del convento de Santa In├®s.', 1930, 1930, 1930, 'Anos 30', 'DELICIAS', 41.65564700, -0.89232100, '0101000020E6100000A91611C5E48DECBF3A5CAB3DECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15060071759.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15060071759.webp', 'https://www.flickr.com/photos/zaragozaantigua/15060071759/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21810, 'Plaza del Portillo 1930', 'Imagen capturada, de buena ma├▒ana, en los jardines de la plaza del Portillo. Al fondo, la iglesia decimon├│nica y hom├│nima, y la despejada vista de ese tramo de la antigua calle del Portillo, entonces recayente a los muros de la enorme huerta conventual de Santa In├®s. Como valor a├▒adido, y en primer├¡simo plano, la sombra del fot├│grafo portugu├®s Ant├│nio Passaporte en el ejercicio de su profesi├│n.', 1930, 1930, 1930, 'Anos 30', 'DELICIAS', 41.65564700, -0.89232100, '0101000020E6100000A91611C5E48DECBF3A5CAB3DECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29783242092.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29783242092.webp', 'https://www.flickr.com/photos/zaragozaantigua/29783242092/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21883, 'La Aljafer├¡a 1931', 'Imagen capturada junto al soterrano cauce de la acequia de la Romareda Baja, o del Boquerazo, en el tramo paralelo a la carretera de Madrid a Francia. Tras los ├írboles y al fondo, explanada de acceso al cuartel de la Aljafer├¡a, cuando era sede de los regimientos de infanter├¡a "Infante" y "Gerona" del Ej├®rcito. Este antiguo palacio presentaba la traza conferida en la reforma que entre 1860-80 lo consolid├│ como dependencia cuartelera, como era tradici├│n desde los albores del siglo XVIII, cuando la Guerra de Sucesi├│n. Sobre el pa├▒o de la fachada principal destacan las marquesinas de los dos accesos. Sobre el tejado emerge la cuadrangular Torre del Trovador, cubierta, y la torrecilla de la iglesia de San Mart├¡n.', 1931, 1931, 1931, 'Anos 30', 'DELICIAS', 41.65598400, -0.89540700, '0101000020E6100000CB80B3942CA7ECBF8159A148F7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49116449481.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49116449481.webp', 'https://www.flickr.com/photos/zaragozaantigua/49116449481/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21991, 'La Aljafer├¡a 1944', 'Imagen capturada durante una inspecci├│n, o revista, del regimiento de artiller├¡a antia├®rea n┬║ 73, llevada a cabo en la explanada de acceso al cuartel de la Aljafer├¡a, cuya luminosa fachada principal aparece al fondo. El ca├▒├│n objeto de admiraci├│n era uno de los impresionantes 8,8-cm-Flak, posiblemente el modelo 36, que los aliados alemanes hab├¡an introducido en la pen├¡nsula durante la guerra de 1936-39 como ayuda del Reich de los 1000 a├▒os a la Espa├▒a nacionalista. El 4 de junio de 1931, el Palacio de la Aljafer├¡a hab├¡a sido declarado Monumento Nacional de Inter├®s Hist├│rico-Art├¡stico. Fuente visual: www.todocoleccion.net/', 1944, 1944, 1944, 'Anos 40', 'DELICIAS', 41.65654200, -0.89635300, '0101000020E6100000D47C957CECAEECBFA839799109D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30897108105.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30897108105.webp', 'https://www.flickr.com/photos/zaragozaantigua/30897108105/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22127, 'P.┬║ de Mar├¡a Agust├¡n 1951', 'Imagen del paseo de Mar├¡a Agust├¡n en su tramo en destacado descenso desde el Portillo, y hasta la Puerta Sancho, abajo. Hacia la izquierda, se abren las calles Teniente Coronel Pueyo, primero, y Aljafer├¡a, despu├®s. Al fondo, donde la pronunciada curva a la derecha, la calle de Santa Luc├¡a lleva a un paso a nivel ferroviario que permite al acceso a la Almozara y la Qu├¡mica. En la despejada calzada, v├¡as del tranv├¡a de la l├¡nea 7 "Ayuntamiento-Puerta Sancho". Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'DELICIAS', 41.65651900, -0.89368000, '0101000020E610000062DBA2CC0699ECBFF01989D008D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23159027235.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23159027235.webp', 'https://www.flickr.com/photos/zaragozaantigua/23159027235/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22352, 'La Aljafer├¡a 1966', 'Cuartel del Pr├¡ncipe en el palacio de la Aljafer├¡a. Fuente: "Espa├▒a, qu├® hermosa eres", 1966.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.65649000, -0.89644500, '0101000020E61000000135B56CADAFECBF551344DD07D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20562363812.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20562363812.webp', 'https://www.flickr.com/photos/zaragozaantigua/20562363812/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22367, 'Paso a nivel de Delicias 1967', 'Imagen del paso a nivel de Delicias con el paseo de Mar├¡a Agust├¡n al fondo, el 24 de junio de 1967. Confluencia de diversos medios de transporte en la actual plaza de la Ciudadan├¡a. Fuente: Asociaci├│n Paso a Nivel.', 1967, 1967, 1967, 'Anos 60', 'DELICIAS', 41.65518200, -0.89805100, '0101000020E6100000AB7B6473D5BCECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21395637735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21395637735.webp', 'https://www.flickr.com/photos/zaragozaantigua/21395637735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22383, 'Calle Boggiero 1962', 'Fielato del Portillo, en la esquina de la calle de Basilio Boggiero (derecha) con el paseo de Mar├¡a Agust├¡n. En la puerta, parte del equipo de la Polic├¡a Sanitaria de Abastos, que controlaba el estado de los productos alimentarios y proced├¡a al cobro de sus tasas. Fuente visual: Bolet├¡n Municipal de Zaragoza.', 1962, 1962, 1962, 'Anos 60', 'DELICIAS', 41.65694400, -0.89343400, '0101000020E6100000874D64E60297ECBFD7A6B1BD16D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22390669160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22390669160.webp', 'https://www.flickr.com/photos/zaragozaantigua/22390669160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22438, 'Paso a nivel Delicias c.1968', 'Continuaci├│n de la imagen anterior, en el entorno del antiguo paso a nivel ferroviario de Delicias. En primer plano, proveniente de la estaci├│n de Campo Sepulcro, traquetea una poderosa locomotora a vapor del tipo 1-5-1, "Santa Fe", pasando junto a la Torre de agujas ferroviarias ubicada en la esquina noreste del paso a nivel. Detr├ís, la estructura del met├ílico puente de se├▒ales ferroviarias, algunos edificios de la avenida de Madrid, y al fondo, el mar de v├¡as de Campo Sepulcro y los grandes bloques de viviendas de la avenida de Anselmo Clav├®. Fuente visual: www.forotrenes.com/', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65548900, -0.89832400, '0101000020E6100000EBC726F911BFECBFA2F14410E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30767140540.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30767140540.webp', 'https://www.flickr.com/photos/zaragozaantigua/30767140540/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22483, 'Av. de Madrid 1968', 'Imagen capturada en el principio de la avenida de Madrid, con el fondo edilicio de la peque├▒a manzana entre la avenida, la calle del Comandante Rodr├¡guez de C├│rdoba, y la calle del Castillo. En el centro de la imagen, el peque├▒o y antiguo inmueble del n┬║ 2 de la calle del Castillo, luego derribado y sustituido por un edificio m├ís moderno y vertical. De fondo, los grandes bloques del ├║ltimo tramo de los n├║meros pares de la calle del General Franco, chaflanero el ├║ltimo con el paseo de Mar├¡a Agust├¡n. A la derecha, vista parcial de las traseras de la iglesia del Portillo. Transita la composici├│n tranviaria M+R n┬║ 108 en servicio en la l├¡nea 5 "Venecia-Delicias", encaminada hacia la plaza de Espa├▒a para ascender luego hasta ese barrio del sur, pasado el Canal Imperial de Arag├│n. Fuente visual: foto Charles F. Firminger en "30937 Transport Photograph Database".', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65603400, -0.89423600, '0101000020E6100000C6FCDCD0949DECBF33880FECF8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40075841073.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40075841073.webp', 'https://www.flickr.com/photos/zaragozaantigua/40075841073/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22519, 'Aljafer├¡a 1966', 'Vista a├®rea centrada en el antiguo palacio de la Aljafer├¡a, todav├¡a bajo jurisdicci├│n militar con funciones cuarteleras. En su aspecto destacan las primeras obras de restauraci├│n acometidas bajo la direcci├│n del arquitecto Francisco ├ì├▒iguez Almech. Rodean al cuartel otras instalaciones militares adosadas y extentas, como su antiguo polvor├¡n y el "hom├│dromo". En primer t├®rmino, naves de la f├íbrica de muebles de Loscertales.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.65663100, -0.89592200, '0101000020E61000008B8A389D64ABECBF17450F7C0CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53286721558.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53286721558.webp', 'https://www.flickr.com/photos/zaragozaantigua/53286721558/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22813, 'P.┬║ de Mar├¡a Agust├¡n 1974', 'In├®dita imagen capturada en la estrat├®gica esquina entre el arranque de la avenida de Madrid y el tramo del paseo de Mar├¡a Agust├¡n que al fondo ofrece su aspecto en ese momento, entre el cuartel del Cid, a la derecha, y las traseras de la iglesia de N.┬¬ S.┬¬ del Portillo. Entre ambos ruinosos entornos se abre la moderna calle que conecta con la plaza del Portillo y que desde 1968 homenajeaba a Jes├║s Muro Sevilla como jefe provincial de Falange Espa├▒ola el 18 de julio de 1936. En primer t├®rmino, frecuentado observatorio o mirador donde algunos de los parroquianos del inmediato Caf├® Madrid (justo a la derecha y fuera de plano), mayormente vinculados con el sector del transporte carretero en cami├│n (ch├│feres, ayudantes, descargadores), "hacen tiempo" entre carga y carga. Algunos de ellos probablemente tendr├ín estacionado el cami├│n en la cercana explanada junto al castillo de la Aljafer├¡a. El inmediato barrio del Castillo, al otro lado de la avenida de Madrid, concentraba un buen n├║mero de despachos de oficina de empresas de transporte.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.65585500, -0.89395800, '0101000020E610000014ECBFCE4D9BECBF84F57F0EF3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51561016174.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51561016174.webp', 'https://www.flickr.com/photos/zaragozaantigua/51561016174/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22864, 'Portillo 1987', 'Desde la torre de la iglesia de N┬¬ S┬¬ del Portillo m├ís cercana a la calle Conde Aranda, un vistazo en altura al sureste urbano de la mano de Luis M├¡nguez, que nos da una buena visual de la inmediata plaza del Portillo, con el estado de las antiguas parcelas del arranque de la calle Pignatelli (izquierda). En l├¡nea recta, varios edificios referenciales de lo que fueran las Eras del Campo del Toro: el Coso de la Misericordia, antes de su cubrimiento, y la antigua Real Casa de la Misericordia, sede de la Diputaci├│n General de Arag├│n desde 1983, en obras de restauraci├│n de su neobizantina iglesia. Al fondo, el edificio Ebrosa, absolutista tope visual. En la calle Madre Rafols, emergen las torres del convento de las Hermanas de la Caridad de Santa Ana. Enfrente, los esquineros y deshabitados edificios para mandos del antiguo cuartel de Sangenis. Por el fondo, y como contrastado tel├│n de fondo, los grandes bloques de la avenida de C├®sar Augusto.', 1987, 1987, 1987, 'Anos 80', 'DELICIAS', 41.65564900, -0.89266600, '0101000020E61000004E098849B890ECBFDA53724EECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15662110277.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15662110277.webp', 'https://www.flickr.com/photos/zaragozaantigua/15662110277/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22904, 'Muebles Loscertales 1989', 'Imagen del acceso a la f├íbrica de muebles de alta gama Sim├│n Loscertales Bona, en la calle Aljafer├¡a, donde terminaba la calle Comandante Rodr├¡guez de C├│rdoba (desde 2009, Sebasti├ín Banzo Urrea), tal y como estaba el 20 de febrero de 1989. Hab├¡a cerrado sus puertas en 1985. Fuente: "Memoria de las calles de Zaragoza", Juli├ín Ruiz Mar├¡n, Librer├¡a General, 2003.', 1989, 1989, 1989, 'Anos 80', 'DELICIAS', 41.65724800, -0.89540900, '0101000020E6100000F96871C630A7ECBF43AED4B320D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21742335371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21742335371.webp', 'https://www.flickr.com/photos/zaragozaantigua/21742335371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22968, 'Restauraci├│n de La Aljafer├¡a 1994', 'Jes├║s Lacueva. La Aljafer├¡a (1994): trabajos de construcci├│n del s├│tano-almac├®n del Patio de las Cortes. El desmoche de la techumbre de enfrente (lado Norte) se practic├│ para colocar la estructura de madera de la sala de comisiones C (despu├®s, sala "Manuel Gim├®nez Abad"); el de la derecha, para ubicar los grupos parlamentarios y la sala "Goya". Fuente: Manuel Ballar├¡n.', 1994, 1994, 1994, 'Anos 90', 'DELICIAS', 41.65637500, -0.89690300, '0101000020E6100000B0E595EB6DB3ECBFBC74931804D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14945038411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14945038411.webp', 'https://www.flickr.com/photos/zaragozaantigua/14945038411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22970, 'Paso a nivel Delicias a├▒os 90', 'A finales de los a├▒os 80 del siglo XX, se decidi├│ que el estado de insalubridad y estrechamiento para los peatones en el paso a nivel ferroviario, carretero y peatonal de Delicias era insostenible. As├¡ que se construy├│ lo que se dio en llamar "Mecano", con su bola blanca gigante posmoderna. En 2001 se desmont├│ y se soterraron las v├¡as.', 1990, 1990, 1999, 'Anos 90', 'DELICIAS', 41.65527500, -0.89784300, '0101000020E610000030293E3E21BBECBF76711B0DE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15009511522.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15009511522.webp', 'https://www.flickr.com/photos/zaragozaantigua/15009511522/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23002, 'Avenida de Madrid a├▒os 90', 'Vista del paso elevado peatonal sobre la avenida de Madrid. Al fondo, barrio de Las Delicias. Fuente: Foto para postal de Comercial Josan. Cesi├│n de la familia de Jos├® Mar├¡a Sanz Gonz├ílez a Rafael Castillejo. Dataci├│n y procesado:', 1990, 1990, 1999, 'Anos 90', 'DELICIAS', 41.65518200, -0.89805100, '0101000020E6100000AB7B6473D5BCECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27321240142.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27321240142.webp', 'https://www.flickr.com/photos/zaragozaantigua/27321240142/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23004, 'Palacio de la Aljafer├¡a a├▒os 90', 'Vista del Palacio de la Aljafer├¡a, una vez concluida su restauraci├│n. Fuente: Foto para postal de Comercial Josan. Cesi├│n de la familia de Jos├® Mar├¡a Sanz Gonz├ílez a Rafael Castillejo. Dataci├│n y procesado:', 1990, 1990, 1999, 'Anos 90', 'DELICIAS', 41.65598100, -0.89714700, '0101000020E61000005D8B16A06DB5ECBF10E6762FF7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27422108855.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27422108855.webp', 'https://www.flickr.com/photos/zaragozaantigua/27422108855/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23035, 'Paso Delicias 1990', 'Imagen capturada desde la altura del inmueble del n┬║ 1 de la calle de Juan XXIII con una panor├ímica vista del entorno del reci├®n inaugurado paso elevado de Delicias, que en el centro de la escena fue construido por el Ayuntamiento para permitir a los peatones atravesar el enlace a la autopista de Logro├▒o, las v├¡as del ferrocarril conducentes a la estaci├│n del Portillo, y dar as├¡ continuidad a la avenida de Madrid de la misma forma que el paso a desnivel permit├¡a al tr├ífico rodado. Esta infraestructura cost├│ 450 millones de pesetas y estuvo en construcci├│n desde mayo de 1988 a abril de 1990. Fue inaugurado oficialmente el 27 de abril de este ├║ltimo a├▒o. En primer t├®rmino y a la izquierda, el colegio p├║blico Juan XXIII, y tras la zona ocupada por las v├¡as del ferrocarril y la autopista, vista del lienzo occidental del palacio de la Aljafer├¡a, que sigue en obras, con la traza preservada del decimon├│nico cuartel. A la derecha, la ancha calle de Escoriaza y Fabro y la de S├ídaba, paralela a las v├¡as, y entre ambas, solar en forma de "quesito" que en 1994 ser├¡a urbanizado.', 1990, 1990, 1990, 'Anos 90', 'DELICIAS', 41.65525400, -0.89804600, '0101000020E610000039B709F7CABCECBF5E49F25CDFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50308514688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50308514688.webp', 'https://www.flickr.com/photos/zaragozaantigua/50308514688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23055, 'Paso a nivel Delicias 1994', 'Imagen, que con el tiempo se convertir├¡a en recurrente, centrada en las escaleras mec├ínicas del reciente paso elevado de Delicias estropeadas, en este caso por los da├▒os producidos por modernos luditas urbanos que encuentran sentido a su vida destrozando el mobiliario p├║blico. Como informa el cartel, para estas ocasiones deb├¡a utilizarse la rampa cuyo uso significaba una notable inversi├│n de tiempo. Al fondo y tras la trinchera ferroviaria, inmueble del principio de la calle de Juan XXIII.', 1994, 1994, 1994, 'Anos 90', 'DELICIAS', 41.65540700, -0.89769200, '0101000020E6100000C72FBC92E4B9ECBFE4486760E4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50446814942.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50446814942.webp', 'https://www.flickr.com/photos/zaragozaantigua/50446814942/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23068, 'Paso Elevado Delicias 2000', '2000. "Paso a Nivel con estructura met├ílica". Construido a finales de los 80 supuestamente para beneficio de las personas a pie, fue desmontado en 2001, con apenas una d├®cada de vida ├║til, a pesar de lo anunciado por el Bolet├¡n (para)Oficial del Ayuntamiento (Revista "Nuestra Zaragoza", agosto-setiembre 1989): "Su dise├▒o y estructura han sido concebidos para convertirse en un punto de referencia de la arquitectura urbana. Para facilitar la vida de los paseantes el Alcalde ha dado instrucciones de que se modifique ligeramente el proyecto de forma que los peatones puedan acceder al paso mediante escaleras mec├ínicas o rampas m├│viles, puesto que los cinco metros de desnivel pueden ser muy fatigosos para personas mayores o que llevan paquetes". Personas mayores, portaquetes, y paseantes en general quedamos muy agradecidos al (ex) Alcalde Trivi├▒o por sus desvelos, se encuentre donde se encuentre.', 2000, 2000, 2000, 'Siglo XXI', 'DELICIAS', 41.65518200, -0.89805100, '0101000020E6100000AB7B6473D5BCECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14785329388.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14785329388.webp', 'https://www.flickr.com/photos/zaragozaantigua/14785329388/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23133, 'Jacques Chirac 2004', 'Foto: Jos├® Miguel Marco. Jacques Chirac, presidente de la Rep├║blica Francesa entre 1995 y 2007, pasea por la Aljafer├¡a flanqueado por el presidente del Reino de Espa├▒a, Jos├® Luis Rodr├¡guez Zapatero, y el de la Comunidad Aut├│noma de Arag├│n, Marcelino Iglesias. Es el 7 de diciembre de 2004, y se celebra la XVII Cumbre hispano-francesa. Fuente: Heraldo de Arag├│n.', 2004, 2004, 2004, 'Siglo XXI', 'DELICIAS', 41.65661900, -0.89682700, '0101000020E6100000F06E6589CEB2ECBF537765170CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31708731961.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31708731961.webp', 'https://www.flickr.com/photos/zaragozaantigua/31708731961/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23198, 'Paseo Mar├¡a Agust├¡n 2015', 'Obras de renovaci├│n de tuber├¡as en el paseo de Mar├¡a Agust├¡n, en su confluencia con la avenida de Madrid (al fondo), en octubre de 2015. Destaca en el centro el estado ruinoso del edificio del antiguo Caf├® Madrid (1889-1997), que alberga el restaurante Casa Emilio (1939). Su fachada fue remozada en 2017. Fuente: www.zaragoza.es', 2015, 2015, 2015, 'Siglo XXI', 'DELICIAS', 41.65607700, -0.89380800, '0101000020E6100000C1E61C3C139AECBF3354C554FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25699741837.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25699741837.webp', 'https://www.flickr.com/photos/zaragozaantigua/25699741837/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23213, 'La Aljafer├¡a 2014', 'Foto: Maroiane B. En agosto de 2014 se difundieron varias fotograf├¡as en las que se reivindicaba al grupo armado integrista ISIS en distintos lugares de Espa├▒a, tras autoproclamar un califato con capital en Mosul, Irak, una vez invadida. En 2017, el gobierno iraqu├¡ recuper├│ esa ciudad. Aqu├¡ podemos ver la bandera de tal organizaci├│n, ante el palacio de la Aljafer├¡a de Zaragoza. La instant├ínea est├í tomada en su esquina noreste, junto al foso. Al fondo, bloque de viviendas de la avenida de Madrid esquinero con la plaza de la Ciudadan├¡a. Fuente: Agencia EFE.', 2014, 2014, 2014, 'Siglo XXI', 'DELICIAS', 41.65718000, -0.89630800, '0101000020E6100000D594641D8EAEECBFEACA67791ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36039001464.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36039001464.webp', 'https://www.flickr.com/photos/zaragozaantigua/36039001464/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23245, 'Saraqusta 1115', '"Sarakosta", dibujo de Jos├® Luis Cano que representa el palacio de la Aljafer├¡a. En el centro, el fil├│sofo Avempace (1080-1139), cuando fue nombrado visir del gobernador almor├ívide Ibn Tifilwit. Fuente: "Zaragoza nuestra ciudad", Ayuntamiento de Zaragoza, 1983.', 1115, 1115, 1115, 'Siglo XIX', 'DELICIAS', 41.65660300, -0.89699900, '0101000020E6100000376E313F37B4ECBF4DBA2D910BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31811731450.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31811731450.webp', 'https://www.flickr.com/photos/zaragozaantigua/31811731450/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23247, 'Saraqusta 1067', 'Fant├ística imagen creada por ordenador para la serie "El Cid" que representa supuestamente la Saraqusta de la Taifa gobernada por Al-Muqt├ídir Billah cuando las tropas del rey Sancho II de Castilla comandadas por ''Ruy'' D├¡az de Vivar se aproximan a ella para cobrar "las parias". La imagen presenta una recreaci├│n muy lograda de una ciudad medieval aparentemente musulmana, con sus murallas, alminares variados y c├║pulas de colores, si bien parece poco probable para la Saraqusta de la ├®poca. Las tropas en su aproximaci├│n por el oeste deber├¡an encontrarse primero con la Al-Ja''Fariyya (La Aljafer├¡a), construcci├│n exenta y fuera del per├¡metro amurallado, que aqu├¡ no aparece cuando deber├¡a hacerlo justo a la izquierda de la puerta de la muralla. Adem├ís el ingreso a la ciudad no era tan desolador por tratarse de una zona regada con el agua de varias acequias (Almozara y Romareda). Y las monta├▒as del fondo no se corresponden con el relieve de la Sierra de Alcubierre.', 1067, 1067, 1067, 'Siglo XIX', 'DELICIAS', 41.65624000, -0.89439800, '0101000020E61000002A73F38DE89EECBFDC291DACFFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51323388974.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51323388974.webp', 'https://www.flickr.com/photos/zaragozaantigua/51323388974/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23248, 'La Aljafer├¡a 1118', 'Portada del c├│mic "Misterio en el valle del Viento", primera entrega de "Las aventuras de F├ítima". Con dibujos de Alfonso Pinedo y guion de Carlos Cabrero y Miguel ├üngel Fec├®, la historieta se sit├║a en los momentos en que Alfonso I el Batallador se dispone a tomar Saraqusta. En la ilustraci├│n, los protagonistas aparecen con el palacio de la Aljafer├¡a detr├ís, minarete incluido. Esta obra rinde homenaje con su estilo al de Herg├®, creador de Tint├¡n.', 1118, 1118, 1118, 'Siglo XIX', 'DELICIAS', 41.65663100, -0.89592200, '0101000020E61000008B8A389D64ABECBF17450F7C0CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52100345769.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52100345769.webp', 'https://www.flickr.com/photos/zaragozaantigua/52100345769/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23252, 'Aljafer├¡a 1737', 'Crist├│bal Cubero. 1737. "Plano del fuerte de la Aljaferia de Zaragoza, con la Plaza de Armas, delante de la principal puerta". El dibujo est├í orientado mirando desde el este. Fuente: www.mcu.es/', 1737, 1737, 1737, 'Siglo XIX', 'DELICIAS', 41.65649000, -0.89644500, '0101000020E61000000135B56CADAFECBF551344DD07D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16616536792.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16616536792.webp', 'https://www.flickr.com/photos/zaragozaantigua/16616536792/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22371, 'Vista a├®rea Parque Grande 1964', 'Vista a├®rea del parque Primo de Rivera y el Cabezo Buenavista con el Jard├¡n de Invierno. Al fondo, el Hospital Militar. M├ís al fondo, el Acampo Casellas y Valdespartera, al suroeste de la ciudad. Fuente: Colecci├│n Rafael Margal├®.', 1964, 1964, 1964, 'Anos 60', 'UNIVERSIDAD', 41.63180200, -0.89279000, '0101000020E610000052448655BC91ECBF11C64FE3DED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21695070983.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21695070983.webp', 'https://www.flickr.com/photos/zaragozaantigua/21695070983/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23262, 'Ctra. de Madrid 1913', 'Imagen capturada junto al arbolado cauce de la acequia de la Romareda Baja, o del Boquerazo, en el tramo paralelo a la carretera de Madrid a Francia, que queda a espaldas del fot├│grafo, delimitado entre la calle del Trovador, hacia la izquierda, y el paseo de Mar├¡a Agust├¡n, hacia la derecha. Al fondo, despejada explanada de acceso al castillo de la Aljafer├¡a, habilitado como dependencia cuartelera del Ej├®rcito. Esta caudalosa acequia hacia la derecha surt├¡a luego la huerta de los conventos de Santa In├®s, de las Carmelitas Descalzas de San Jos├® o Fecetas, y de Santa Luc├¡a, adem├ís de al lavadero de la Sierra de Agua, ya en la calle del Veintinueve de Septiembre, para terminar derivando en la acequia Mayor de la Almozara, un poco antes de su desemboque en el r├¡o Ebro.', 1913, 1913, 1913, 'Anos 10', 'DELICIAS', 41.65598400, -0.89459100, '0101000020E61000004F78094E7DA0ECBF8159A148F7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48576393371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48576393371.webp', 'https://www.flickr.com/photos/zaragozaantigua/48576393371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23265, 'Aljafer├¡a c.1895', 'Imagen centrada en el castillo de la Aljafer├¡a habilitado como cuartel del ramo de la Guerra para acoger al regimiento de infanter├¡a del Infante N┬║ 5 y el regimineto de Gerona N┬║ 22. En primer t├®rmino, curso al aire de la acequia Baja de la Romareda, tambi├®n denominada del "Boquerazo" que, proveniente del camino de la Mosquetera, y tras cruzar soterrada la carretera de Madrid a Francia contin├║a hacia la derecha para cruzar el paseo de Mar├¡a Agust├¡n y dirigirse hacia los conventos de Santa In├®s y de las Fecetas.', 1895, 1895, 1895, 'Siglo XIX', 'DELICIAS', 41.65587900, -0.89551400, '0101000020E61000004D86E3F90CA8ECBF0C91D3D7F3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54162313102.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54162313102.webp', 'https://www.flickr.com/photos/zaragozaantigua/54162313102/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23269, 'La Aljafer├¡a 1808', '"Bater├¡a del Portillo. Donde, al ver sus defensores caer muertos o heridos sin quedar quien sirviese la artiller├¡a, la intr├®pida Agustina Arag├│n, saltando por encima de los cad├íveres arrebat├│ la mecha de manos de un artillero que acababa de expirar; y haciendo fuego con gallarda bizarr├¡a ataj├│ el ├¡mpetu furioso de los enemigos en el ataque del 4 de julio". Serie Ruinas de Zaragoza, de Juan G├ílvez (dibujo) y Fernando Brambila (grabado), C├ídiz, 1812. Al fondo vemos la Aljafer├¡a, a la derecha de una torre agr├¡cola. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'DELICIAS', 41.65613800, -0.89280000, '0101000020E610000036CD3B4ED191ECBFD8D47954FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15244962776.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15244962776.webp', 'https://www.flickr.com/photos/zaragozaantigua/15244962776/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23438, 'La Aljafer├¡a 1983', 'Excavaci├│n en La Aljafer├¡a para recuperar el foso de Tiburzio Spanochi de finales del siglo XVI. A la izquierda, el recreado pa├▒o oriental palaciego por el que se acced├¡a a la nueva sede de las Cortes de Arag├│n. En primer t├®rmino, camiones aparcados en esta zona con fuerte presencia del sector del transporte interurbano de mercanc├¡as. Al fondo, la industrial Qu├¡mica y el barrio de La Almozara. La foto est├í tomada desde cierta altura en el inmueble del n┬║ 33 de la avenida de Madrid.', 1983, 1983, 1983, 'Anos 80', 'DELICIAS', 41.65626900, -0.89677100, '0101000020E6100000F609A01859B2ECBF7730629F00D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14871802947.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14871802947.webp', 'https://www.flickr.com/photos/zaragozaantigua/14871802947/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23439, 'Panor├ímica Aljafer├¡a 1973', 'El castillo de la Aljafer├¡a centra esta vista en altura capturada desde el reciente bloque del n┬║ 31 de la avenida de Madrid. Se estaba realizando, seg├║n el proyecto de Francisco ├ì├▒iguez, la reconstrucci├│n de la puerta de acceso, los dos torreones que la flanquean y el resto de cubos del lienzo oriental de la muralla, con el torre├│n de ├íngulo y su enlace con la torre del Homenaje. El proceso de restauraci├│n se prolong├│ durante d├®cadas, desde que ese arquitecto lo emprendiese en 1947 y hasta su muerte en 1982. El Ayuntamiento, propietario del inmueble desde 1978, lo cedi├│ en 1984 a las Cortes de Arag├│n para establecer all├¡ su sede. En la panor├ímica y de izquierda a derecha: el paso a nivel del ferrocarril y la avenida de Madrid, que se├▒alan el acceso hacia el populoso barrio de Las Delicias; el entorno del palacio de la Aljafer├¡a, que conserva varias construcciones de car├ícter militar, e incluye la inevitable explanada como aparcamiento de camiones; las naves de la Industrial Qu├¡mica de Zaragoza y las v├¡as del ferrocarril. Al fondo van creciendo altas edificaciones en el barrio de La Almozara.', 1973, 1973, 1973, 'Anos 70', 'DELICIAS', 41.65551900, -0.89550300, '0101000020E610000053094FE8F5A7ECBF0C74ED0BE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14875982386.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14875982386.webp', 'https://www.flickr.com/photos/zaragozaantigua/14875982386/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23447, 'La Aljafer├¡a 1593', 'Dibujo de la Aljafer├¡a de Zaragoza, en la parte de Levante. Tiburcio Spanochi, 1593. Archivo General de Simancas, Ministerio de Cultura de Espa├▒a. "Este singular edificio sufri├│ a lo largo de nueve siglos una compleja metamorfosis que lo presenta como un crisol de culturas y hechos hist├│ricos. Los mayores cambios se producen en la Edad Moderna. Se destina a sede y prisi├│n del Tribunal del Santo Oficio. Tras las alteraciones de Arag├│n de 1591, Felipe II propone al ingeniero Tiburcio Spanochi su fortificaci├│n y transformaci├│n en ciudadela. El proyecto se realiza en 1593 rodeando el palacio de un foso con baluartes. La fortaleza se construye de argamasa y ladrillos con cadenas de sillares en las esquinas, siendo las dos puertas, sobre todo la principal de este dibujo, las que concentran la decoraci├│n. Su funci├│n palatina dar├í paso al uso militar que mantuvo hasta mediados del siglo XX."', 1593, 1593, 1593, 'Siglo XIX', 'DELICIAS', 41.65651600, -0.89631200, '0101000020E61000003065E08096AEECBF7FA65EB708D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15061057811.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15061057811.webp', 'https://www.flickr.com/photos/zaragozaantigua/15061057811/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23453, 'La Aljafer├¡a 1998', 'A├®rea vista de la ciudad con el Palacio de la Aljafer├¡a como hito fundamental, visto desde el oeste. Tras la decisi├│n tomada en 1985 de ubicar aqu├¡ a las Cortes de Arag├│n, la imagen del edificio se corresponde con las labores de adecuaci├│n del mismo a funciones y utilidades para las que no estaba pensado, con una compleja cohabitaci├│n de espacios institucionales y muse├¡sticos, que se inclinan siempre en beneficio de los corporativos intereses de quienes est├ín detr├ís del foso. Fuente visual: "La Aljafer├¡a", Cortes de Arag├│n, 1998.', 1998, 1998, 1998, 'Anos 90', 'DELICIAS', 41.65650600, -0.89697200, '0101000020E6100000D1AFAD9FFEB3ECBF5BD07B6308D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15319745870.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15319745870.webp', 'https://www.flickr.com/photos/zaragozaantigua/15319745870/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23455, 'La Aljafer├¡a 1973', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. Junio 1973. Imagen del Castillo de la Aljafer├¡a, cuando se estaba realizando, seg├║n el proyecto de Francisco ├ì├▒iguez, la reconstrucci├│n de la puerta de acceso de la muralla, de los dos torreones que la flanquean y del resto de la muralla del lienzo este, con el torre├│n de ├íngulo y su enlace con la torre del Homenaje. Para la reconstrucci├│n de los torreones cil├¡ndricos, ├ì├▒iguez tuvo en cuenta los alzados de Spanochi de 1593 y los alzados y plantas de Miguel Mar├¡n de 1757. Las obras de intervenci├│n en la Aljafer├¡a, en sus diversas fases, se extendieron desde 1955 hasta 1997.', 1973, 1973, 1973, 'Anos 70', 'DELICIAS', 41.65671300, -0.89653300, '0101000020E6100000D21C59F965B0ECBFD5EDEC2B0FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15380138162.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15380138162.webp', 'https://www.flickr.com/photos/zaragozaantigua/15380138162/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23467, 'La Aljafer├¡a 1860', 'Vista de la fachada principal del palacio de la Aljafer├¡a. Detr├ís sobresalen la torre del Trovador y la de la capilla de San Mart├¡n. Fuente: Mariano J├║dez y Ortiz. ├ülbum de Andr├®s Mart├¡n e Ip├ís. Colecci├│n Mariano Mart├¡n Casalderrey. Libro Primeros tiempos de la fotograf├¡a en Zaragoza.', 1860, 1860, 1860, 'Siglo XIX', 'DELICIAS', 41.65654200, -0.89635300, '0101000020E6100000D47C957CECAEECBFA839799109D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28489798401.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28489798401.webp', 'https://www.flickr.com/photos/zaragozaantigua/28489798401/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
